{
  "name": "SmartScout Resume Scorer",
  "description": "An AI-powered resume analysis and scoring tool that compares multiple CVs against a job description with detailed parameter-based breakdowns and interactive visualizations."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface ScoringBreakdown {
  parameter: string;
  score: number;
  maxScore: number;
  reasoning: string;
}

export interface AnalysisResult {
  candidateName: string;
  overallScore: number;
  breakdown: ScoringBreakdown[];
  summary: string;
  strengths: string[];
  gaps: string[];
  recommendation: 'Highly Recommend' | 'Recommend' | 'Consider' | 'Reject';
}

export interface ResumeFile {
  id: string;
  name: string;
  type: string;
  content: string; // Base64 or plain text
  status: 'pending' | 'processing' | 'completed' | 'error';
  result?: AnalysisResult;
}

export interface ChatMessage {
  role: 'user' | 'assistant';
  content: string;
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { AnalysisResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeResume = async (
  jd: string,
  resumeData: { name: string; type: string; content: string }
): Promise<AnalysisResult> => {
  const model = "gemini-3-flash-preview";

  const prompt = `
    Task: Act as an expert HR Recruiter. Analyze the provided Resume against the Job Description (JD).

    Job Description:
    ${jd}

    Instructions:
    1. Extract the candidate's name from the resume.
    2. Score the candidate on a scale of 0-100 across 5 parameters: Technical Skills, Soft Skills, Relevant Experience, Education Alignment, and Overall Cultural Fit.
    3. Provide a concise summary of the candidate's profile.
    4. List exactly 3 key strengths and exactly 3 key gaps.
    5. Provide a final recommendation.
  `;

  const isImage = resumeData.type.startsWith('image/');

  const contents = isImage 
    ? {
        parts: [
          { text: prompt },
          { inlineData: { mimeType: resumeData.type, data: resumeData.content } }
        ]
      }
    : {
        parts: [
          { text: prompt },
          { text: `Resume Content:\n${resumeData.content}` }
        ]
      };

  const response = await ai.models.generateContent({
    model,
    contents,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          candidateName: { type: Type.STRING },
          overallScore: { type: Type.NUMBER },
          breakdown: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                parameter: { type: Type.STRING },
                score: { type: Type.NUMBER },
                maxScore: { type: Type.NUMBER },
                reasoning: { type: Type.STRING }
              },
              required: ["parameter", "score", "maxScore", "reasoning"]
            }
          },
          summary: { type: Type.STRING },
          strengths: { type: Type.ARRAY, items: { type: Type.STRING } },
          gaps: { type: Type.ARRAY, items: { type: Type.STRING } },
          recommendation: { type: Type.STRING }
        },
        required: ["candidateName", "overallScore", "breakdown", "summary", "strengths", "gaps", "recommendation"]
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("Empty response from AI");

  return JSON.parse(text) as AnalysisResult;
};

export const chatWithContext = async (
  jd: string,
  analysis: AnalysisResult[],
  messages: { role: 'user' | 'assistant'; content: string }[]
): Promise<string> => {
  const chat = ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      systemInstruction: `You are an AI HR Assistant. You have analyzed several resumes against a specific job description.

      Job Description: ${jd}

      Candidates Analyzed:
      ${analysis.map(a => `${a.candidateName}: Score ${a.overallScore}, Summary: ${a.summary}`).join('\n')}

      Answer user questions about the candidates, their scores, and comparisons between them based strictly on the analysis provided. Be professional, objective, and helpful.`
    }
  });

  const lastMessage = messages[messages.length - 1].content;
  const response = await chat.sendMessage({ message: lastMessage });
  return response.text || "Sorry, I couldn't generate a response.";
};

