import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import JDInput from './components/JDInput';
import FileUpload from './components/FileUpload';
import AnalysisDashboard from './components/AnalysisDashboard';
import ChatInterface from './components/ChatInterface';
import { ResumeFile, AnalysisResult } from './types';
import { analyzeResume } from './services/geminiService';

const App: React.FC = () => {
  const [jd, setJd] = useState('');
  const [resumes, setResumes] = useState<ResumeFile[]>([]);
  const [activeTab, setActiveTab] = useState<'input' | 'dashboard' | 'chat'>('input');
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const handleUpload = async (files: FileList) => {
    const newFiles: ResumeFile[] = [];

    for (let i = 0; i < files.length; i++) {
      const file = files[i];
      const id = Math.random().toString(36).substr(2, 9);

      const reader = new FileReader();
      const contentPromise = new Promise<string>((resolve) => {
        reader.onload = () => {
          const result = reader.result as string;
          // For images, we need the base64 part only
          if (file.type.startsWith('image/')) {
            resolve(result.split(',')[1]);
          } else {
            resolve(result);
          }
        };
        if (file.type.startsWith('image/')) {
          reader.readAsDataURL(file);
        } else {
          reader.readAsText(file);
        }
      });

      const content = await contentPromise;
      newFiles.push({
        id,
        name: file.name,
        type: file.type,
        content,
        status: 'pending'
      });
    }

    setResumes(prev => [...prev, ...newFiles]);
  };

  const removeResume = (id: string) => {
    setResumes(prev => prev.filter(f => f.id !== id));
  };

  const startAnalysis = async () => {
    if (!jd.trim() || resumes.length === 0) return;

    setIsAnalyzing(true);
    setActiveTab('dashboard');

    const updatedResumes = [...resumes];

    for (let i = 0; i < updatedResumes.length; i++) {
      if (updatedResumes[i].status === 'completed') continue;

      try {
        updatedResumes[i].status = 'processing';
        setResumes([...updatedResumes]);

        const result = await analyzeResume(jd, {
          name: updatedResumes[i].name,
          type: updatedResumes[i].type,
          content: updatedResumes[i].content
        });

        updatedResumes[i].result = result;
        updatedResumes[i].status = 'completed';
      } catch (error) {
        console.error("Error analyzing resume:", error);
        updatedResumes[i].status = 'error';
      }
      setResumes([...updatedResumes]);
    }

    setIsAnalyzing(false);
  };

  const completedAnalyses = resumes
    .filter(r => r.status === 'completed' && r.result)
    .map(r => r.result as AnalysisResult);

  return (
    <Layout 
      activeTab={activeTab} 
      setActiveTab={setActiveTab}
      canDashboard={resumes.some(r => r.status === 'completed' || r.status === 'processing')}
    >
      {activeTab === 'input' && (
        <div className="space-y-8 animate-fadeIn">
          <div className="flex flex-col md:flex-row gap-8">
            <div className="flex-1 space-y-4">
              <h3 className="text-lg font-bold text-slate-800">1. Define Requirements</h3>
              <JDInput value={jd} onChange={setJd} />
            </div>
            <div className="flex-1 space-y-4">
              <h3 className="text-lg font-bold text-slate-800">2. Upload Candidates</h3>
              <FileUpload resumes={resumes} onUpload={handleUpload} onRemove={removeResume} />
            </div>
          </div>

          <div className="flex justify-center pt-8">
            <button
              onClick={startAnalysis}
              disabled={!jd.trim() || resumes.length === 0 || isAnalyzing}
              className={`px-10 py-4 rounded-xl font-bold text-lg shadow-xl transition-all transform hover:scale-105 flex items-center gap-3 ${
                !jd.trim() || resumes.length === 0 || isAnalyzing
                  ? 'bg-slate-200 text-slate-400 cursor-not-allowed'
                  : 'bg-blue-600 text-white hover:bg-blue-700 active:bg-blue-800'
              }`}
            >
              {isAnalyzing ? (
                <>
                  <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Processing...
                </>
              ) : (
                <>
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
                  </svg>
                  Run Full Analysis
                </>
              )}
            </button>
          </div>
        </div>
      )}

      {activeTab === 'dashboard' && (
        <AnalysisDashboard results={completedAnalyses} isAnalyzing={isAnalyzing} />
      )}

      {activeTab === 'chat' && (
        <ChatInterface jd={jd} results={completedAnalyses} />
      )}
    </Layout>
  );
};

export default App;

import React from 'react';
import { ResumeFile } from '../types';

interface FileUploadProps {
  resumes: ResumeFile[];
  onUpload: (files: FileList) => void;
  onRemove: (id: string) => void;
}

const FileUpload: React.FC<FileUploadProps> = ({ resumes, onUpload, onRemove }) => {
  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      onUpload(e.target.files);
    }
  };

  return (
    <div className="space-y-4">
      <div className="border-2 border-dashed border-slate-300 rounded-xl p-8 text-center bg-white hover:border-blue-400 hover:bg-blue-50 transition-all cursor-pointer group relative">
        <input
          type="file"
          multiple
          accept=".pdf,.png,.jpg,.jpeg,text/plain"
          className="absolute inset-0 opacity-0 cursor-pointer"
          onChange={handleFileChange}
        />
        <div className="flex flex-col items-center">
          <div className="w-12 h-12 bg-blue-100 rounded-full flex items-center justify-center mb-4 group-hover:scale-110 transition-transform">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-blue-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
            </svg>
          </div>
          <p className="text-slate-700 font-medium">Click or drag resumes</p>
          <p className="text-xs text-slate-400 mt-1 uppercase tracking-tight">Images, Text or PDFs</p>
        </div>
      </div>

      <div className="grid grid-cols-1 gap-3 max-h-[400px] overflow-y-auto custom-scrollbar pr-2">
        {resumes.map((file) => (
          <div key={file.id} className="bg-white p-4 rounded-lg border border-slate-200 flex items-center justify-between group animate-fadeIn shadow-sm">
            <div className="flex items-center gap-3 overflow-hidden">
              <div className={`p-2 rounded-lg ${file.type.includes('image') ? 'bg-purple-100 text-purple-600' : 'bg-blue-100 text-blue-600'}`}>
                {file.type.includes('image') ? (
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                  </svg>
                ) : (
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                  </svg>
                )}
              </div>
              <div className="truncate">
                <p className="text-sm font-semibold text-slate-800 truncate">{file.name}</p>
                <div className="flex items-center gap-2">
                  <span className={`text-[10px] font-bold uppercase ${
                    file.status === 'completed' ? 'text-green-500' : 
                    file.status === 'processing' ? 'text-blue-500' : 
                    file.status === 'error' ? 'text-red-500' : 'text-slate-400'
                  }`}>
                    {file.status}
                  </span>
                </div>
              </div>
            </div>

            <button
              onClick={() => onRemove(file.id)}
              className="text-slate-300 hover:text-red-500 p-2 rounded-full hover:bg-red-50 transition-all"
              title="Remove file"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
              </svg>
            </button>
          </div>
        ))}
        {resumes.length === 0 && (
          <div className="text-center py-8 text-slate-400 text-sm">
            No files uploaded yet.
          </div>
        )}
      </div>
    </div>
  );
};

export default FileUpload;

import React, { useState } from 'react';
import { AnalysisResult } from '../types';

interface AnalysisDashboardProps {
  results: AnalysisResult[];
  isAnalyzing: boolean;
}

const AnalysisDashboard: React.FC<AnalysisDashboardProps> = ({ results, isAnalyzing }) => {
  const [selectedCandidate, setSelectedCandidate] = useState<string | null>(null);

  if (results.length === 0 && isAnalyzing) {
    return (
      <div className="flex flex-col items-center justify-center h-full py-20 text-center">
        <div className="relative">
          <div className="w-20 h-20 border-4 border-blue-100 border-t-blue-600 rounded-full animate-spin"></div>
          <div className="absolute inset-0 flex items-center justify-center">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-blue-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
            </svg>
          </div>
        </div>
        <h3 className="mt-6 text-xl font-bold text-slate-800">Analyzing Resumes...</h3>
        <p className="text-slate-500 mt-2 max-w-md mx-auto">Our AI is reading through the profiles, matching skills against your JD, and calculating scores.</p>
      </div>
    );
  }

  if (results.length === 0) {
    return (
      <div className="text-center py-20">
        <div className="bg-slate-100 rounded-full w-20 h-20 flex items-center justify-center mx-auto mb-4">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 17v-2m3 2v-4m3 4v-6m2 10H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
          </svg>
        </div>
        <h3 className="text-lg font-medium text-slate-700">No Analysis Yet</h3>
        <p className="text-slate-500">Upload resumes and run the analysis to see rankings here.</p>
      </div>
    );
  }

  // Sort results by overall score descending
  const sortedResults = [...results].sort((a, b) => b.overallScore - a.overallScore);

  return (
    <div className="space-y-8 pb-12">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-slate-800">Top Candidates</h2>
        <span className="px-3 py-1 bg-green-100 text-green-700 text-sm font-semibold rounded-full">
          {results.length} Processed
        </span>
      </div>

      <div className="grid grid-cols-1 gap-6">
        {sortedResults.map((candidate, index) => (
          <div 
            key={index} 
            className={`bg-white rounded-xl shadow-sm border overflow-hidden transition-all duration-300 ${
              selectedCandidate === candidate.candidateName ? 'ring-2 ring-blue-500 border-transparent shadow-lg' : 'border-slate-200 hover:shadow-md'
            }`}
          >
            {/* Header Section */}
            <div 
              className="p-6 cursor-pointer flex flex-col md:flex-row md:items-center justify-between gap-6"
              onClick={() => setSelectedCandidate(selectedCandidate === candidate.candidateName ? null : candidate.candidateName)}
            >
              <div className="flex items-center gap-4">
                <div className={`w-12 h-12 rounded-full flex items-center justify-center text-lg font-bold ${
