import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { AnalysisResult, InterviewQuestions } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeResume = async (
  jd: string,
  resumeData: { name: string; type: string; content: string }
): Promise<AnalysisResult> => {
  const model = "gemini-3-flash-preview";

  const prompt = `
    Task: Act as an expert HR Recruiter. Analyze the provided Resume against the Job Description (JD).

    Job Description:
    ${jd}

    Instructions:
    1. Extract the candidate's name from the resume. If no clear name is found, use the filename as a placeholder.
    2. Score the candidate on a scale of 0-100 across 5 parameters: Technical Skills, Soft Skills, Relevant Experience, Education Alignment, and Overall Cultural Fit.
    3. Provide a concise summary of the candidate's profile.
    4. List exactly 3 key strengths and exactly 3 key gaps.
    5. Provide a final recommendation ('Highly Recommend', 'Recommend', 'Consider', 'Reject').
  `;

  const isImage = resumeData.type.startsWith('image/');

  const contents = isImage 
    ? {
        parts: [
          { text: prompt },
          { inlineData: { mimeType: resumeData.type, data: resumeData.content } }
        ]
      }
    : {
        parts: [
          { text: prompt },
          { text: `Resume Content:\n${resumeData.content}` }
        ]
      };

  const response = await ai.models.generateContent({
    model,
    contents,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          candidateName: { type: Type.STRING },
          overallScore: { type: Type.NUMBER },
          breakdown: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                parameter: { type: Type.STRING },
                score: { type: Type.NUMBER },
                maxScore: { type: Type.NUMBER },
                reasoning: { type: Type.STRING }
              },
              required: ["parameter", "score", "maxScore", "reasoning"]
            }
          },
          summary: { type: Type.STRING },
          strengths: { type: Type.ARRAY, items: { type: Type.STRING } },
          gaps: { type: Type.ARRAY, items: { type: Type.STRING } },
          recommendation: { type: Type.STRING }
        },
        required: ["candidateName", "overallScore", "breakdown", "summary", "strengths", "gaps", "recommendation"]
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("Empty response from AI");

  return JSON.parse(text) as AnalysisResult;
};

export const generateInterviewQuestions = async (
  jd: string,
  analysis: AnalysisResult
): Promise<InterviewQuestions> => {
  const model = "gemini-3-flash-preview";

  const prompt = `
    Act as a senior hiring manager preparing for an interview. Based on the Job Description and the candidate's analysis (summary, strengths, and gaps), generate insightful, open-ended interview questions.

    - Generate exactly 2 questions to validate their key strengths and understand the depth of their expertise.
    - Generate exactly 2 questions to probe their potential gaps or areas for development in a constructive manner.

    Job Description:
    ${jd}

    Candidate Analysis:
    Name: ${analysis.candidateName}
    Summary: ${analysis.summary}
    Strengths: ${analysis.strengths.join(', ')}
    Gaps: ${analysis.gaps.join(', ')}
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          strengths: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "Questions to validate candidate's strengths."
          },
          gaps: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "Questions to probe candidate's gaps."
          }
        },
        required: ["strengths", "gaps"]
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("Empty response from AI");

  return JSON.parse(text) as InterviewQuestions;
}

export const chatWithContext = async (
  jd: string,
  analysis: AnalysisResult[],
  messages: { role: 'user' | 'assistant'; content: string }[]
): Promise<string> => {
  const chat = ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      systemInstruction: `You are an AI HR Assistant. You have analyzed several resumes against a specific job description.

      Job Description: ${jd}

      Candidates Analyzed:
      ${analysis.map(a => `${a.candidateName}: Score ${a.overallScore}, Summary: ${a.summary}`).join('\n')}

      Answer user questions about the candidates, their scores, and comparisons between them based strictly on the analysis provided. Be professional, objective, and helpful.`
    }
  });

  const lastMessage = messages[messages.length - 1].content;
  const response = await chat.sendMessage({ message: lastMessage });
  return response.text || "Sorry, I couldn't generate a response.";
};

import React, { useState } from 'react';
import { AnalysisResult, InterviewQuestions } from '../types';
import { generateInterviewQuestions } from '../services/geminiService';

interface AnalysisDashboardProps {
  results: AnalysisResult[];
  isAnalyzing: boolean;
  jd: string; // Pass JD for context
}

const AnalysisDashboard: React.FC<AnalysisDashboardProps> = ({ results, isAnalyzing, jd }) => {
  const [selectedCandidate, setSelectedCandidate] = useState<string | null>(null);
  const [generatedQuestions, setGeneratedQuestions] = useState<Record<string, InterviewQuestions>>({});
  const [questionLoading, setQuestionLoading] = useState<Record<string, boolean>>({});

  const handleGenerateQuestions = async (candidate: AnalysisResult) => {
    if (!jd || generatedQuestions[candidate.candidateName]) return;

    setQuestionLoading(prev => ({ ...prev, [candidate.candidateName]: true }));
    try {
      const questions = await generateInterviewQuestions(jd, candidate);
      setGeneratedQuestions(prev => ({ ...prev, [candidate.candidateName]: questions }));
    } catch (error) {
      console.error("Error generating interview questions:", error);
      // Optionally, set an error state to show in the UI
    } finally {
      setQuestionLoading(prev => ({ ...prev, [candidate.candidateName]: false }));
    }
  };

  if (results.length === 0 && isAnalyzing) {
    return (
      <div className="flex flex-col items-center justify-center h-full py-20 text-center">
        <div className="relative">
          <div className="w-20 h-20 border-4 border-blue-100 border-t-blue-600 rounded-full animate-spin"></div>
          <div className="absolute inset-0 flex items-center justify-center">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-blue-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
            </svg>
          </div>
        </div>
        <h3 className="mt-6 text-xl font-bold text-slate-800">Analyzing Resumes...</h3>
        <p className="text-slate-500 mt-2 max-w-md mx-auto">Our AI is reading through the profiles, matching skills against your JD, and calculating scores.</p>
      </div>
    );
  }

  if (results.length === 0) {
    return (
      <div className="text-center py-20">
        <div className="bg-slate-100 rounded-full w-20 h-20 flex items-center justify-center mx-auto mb-4">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 17v-2m3 2v-4m3 4v-6m2 10H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
          </svg>
        </div>
        <h3 className="text-lg font-medium text-slate-700">No Analysis Yet</h3>
        <p className="text-slate-500">Upload resumes and run the analysis to see rankings here.</p>
      </div>
    );
  }

  const sortedResults = [...results].sort((a, b) => b.overallScore - a.overallScore);

  return (
    <div className="space-y-8 pb-12">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-slate-800">Top Candidates</h2>
        <span className="px-3 py-1 bg-green-100 text-green-700 text-sm font-semibold rounded-full">
          {results.length} Processed
        </span>
      </div>

      <div className="grid grid-cols-1 gap-6">
        {sortedResults.map((candidate, index) => (
          <div 
            key={index} 
            className={`bg-white rounded-xl shadow-sm border overflow-hidden transition-all duration-300 ${
              selectedCandidate === candidate.candidateName ? 'ring-2 ring-blue-500 border-transparent shadow-lg' : 'border-slate-200 hover:shadow-md'
            }`}
          >
            <div 
              className="p-6 cursor-pointer flex flex-col md:flex-row md:items-center justify-between gap-6"
              onClick={() => setSelectedCandidate(selectedCandidate === candidate.candidateName ? null : candidate.candidateName)}
            >
              {/* ... existing header section ... */}
            </div>

            {selectedCandidate === candidate.candidateName && (
              <div className="border-t border-slate-100 bg-slate-50 p-6 md:p-8 animate-fadeIn">
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                  {/* ... existing breakdown and summary ... */}
                </div>

                {/* Interview Questions Section */}
                <div className="mt-8 pt-6 border-t border-slate-200">
                  <h4 className="font-semibold text-slate-800 mb-4 flex items-center gap-2">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-blue-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" /></svg>
                    Suggested Interview Questions
                  </h4>
                  {!generatedQuestions[candidate.candidateName] && !questionLoading[candidate.candidateName] && (
                    <button 
                      onClick={() => handleGenerateQuestions(candidate)}
                      className="px-4 py-2 bg-blue-100 text-blue-700 font-semibold rounded-lg hover:bg-blue-200 transition-all text-sm flex items-center gap-2"
