import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import JDInput from './components/JDInput';
import FileUpload from './components/FileUpload';
import AnalysisDashboard from './components/AnalysisDashboard';
import ChatInterface from './components/ChatInterface';
import { ResumeFile, AnalysisResult } from './types';
import { analyzeResume } from './services/geminiService';

const App: React.FC = () => {
  const [jd, setJd] = useState('');
  const [resumes, setResumes] = useState<ResumeFile[]>([]);
  const [activeTab, setActiveTab] = useState<'input' | 'dashboard' | 'chat'>('input');
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const handleUpload = async (files: FileList) => {
    const newFiles: ResumeFile[] = [];

    for (let i = 0; i < files.length; i++) {
      const file = files[i];
      const id = Math.random().toString(36).substr(2, 9);

      const reader = new FileReader();
      const contentPromise = new Promise<string>((resolve) => {
        reader.onload = () => {
          const result = reader.result as string;
          // For images, we need the base64 part only
          if (file.type.startsWith('image/')) {
            resolve(result.split(',')[1]);
          } else {
            resolve(result);
          }
        };
        if (file.type.startsWith('image/')) {
          reader.readAsDataURL(file);
        } else {
          reader.readAsText(file);
        }
      });

      const content = await contentPromise;
      newFiles.push({
        id,
        name: file.name,
        type: file.type,
        content,
        status: 'pending'
      });
    }

    setResumes(prev => [...prev, ...newFiles]);
  };

  const removeResume = (id: string) => {
    setResumes(prev => prev.filter(f => f.id !== id));
  };

  const startAnalysis = async () => {
    if (!jd.trim() || resumes.length === 0) return;

    setIsAnalyzing(true);
    setActiveTab('dashboard');

    const updatedResumes = [...resumes];

    for (let i = 0; i < updatedResumes.length; i++) {
      if (updatedResumes[i].status === 'completed') continue;

      try {
        updatedResumes[i].status = 'processing';
        setResumes([...updatedResumes]);

        const result = await analyzeResume(jd, {
          name: updatedResumes[i].name,
          type: updatedResumes[i].type,
          content: updatedResumes[i].content
        });

        updatedResumes[i].result = result;
        updatedResumes[i].status = 'completed';
      } catch (error) {
        console.error("Error analyzing resume:", error);
        updatedResumes[i].status = 'error';
      }
      setResumes([...updatedResumes]);
    }

    setIsAnalyzing(false);
  };

  const completedAnalyses = resumes
    .filter(r => r.status === 'completed' && r.result)
    .map(r => r.result as AnalysisResult);

  return (
    <Layout 
      activeTab={activeTab} 
      setActiveTab={setActiveTab}
      canDashboard={resumes.some(r => r.status === 'completed' || r.status === 'processing')}
    >
      {activeTab === 'input' && (
        <div className="space-y-8 animate-fadeIn">
          <div className="flex flex-col md:flex-row gap-8">
            <div className="flex-1 space-y-4">
              <h3 className="text-lg font-bold text-slate-800">1. Define Requirements</h3>
              <JDInput value={jd} onChange={setJd} />
            </div>
            <div className="flex-1 space-y-4">
              <h3 className="text-lg font-bold text-slate-800">2. Upload Candidates</h3>
              <FileUpload resumes={resumes} onUpload={handleUpload} onRemove={removeResume} />
            </div>
          </div>

          <div className="flex justify-center pt-8">
            <button
              onClick={startAnalysis}
              disabled={!jd.trim() || resumes.length === 0 || isAnalyzing}
              className={`px-10 py-4 rounded-xl font-bold text-lg shadow-xl transition-all transform hover:scale-105 flex items-center gap-3 ${
                !jd.trim() || resumes.length === 0 || isAnalyzing
                  ? 'bg-slate-200 text-slate-400 cursor-not-allowed'
                  : 'bg-blue-600 text-white hover:bg-blue-700 active:bg-blue-800'
              }`}
            >
              {isAnalyzing ? (
                <>
                  <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Processing...
                </>
              ) : (
                <>
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
                  </svg>
                  Run Full Analysis
                </>
              )}
            </button>
          </div>
        </div>
      )}

      {activeTab === 'dashboard' && (
        <AnalysisDashboard results={completedAnalyses} isAnalyzing={isAnalyzing} jd={jd} />
      )}

      {activeTab === 'chat' && (
        <ChatInterface jd={jd} results={completedAnalyses} />
      )}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import JDInput from './components/JDInput';
import FileUpload from './components/FileUpload';
import AnalysisDashboard from './components/AnalysisDashboard';
import { ResumeFile, AnalysisResult } from './types';
import { analyzeResume } from './services/geminiService';

const App: React.FC = () => {
  const [jd, setJd] = useState('');
  const [resumes, setResumes] = useState<ResumeFile[]>([]);
  const [view, setView] = useState<'setup' | 'dashboard'>('setup');
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const handleUpload = async (files: FileList) => {
    const newFiles: ResumeFile[] = Array.from(files).map(file => {
      const id = Math.random().toString(36).substr(2, 9);
      return {
        id,
        name: file.name,
        type: file.type,
        file, // Store the file object
        content: '', // Will be loaded on demand
        status: 'pending'
      } as ResumeFile;
    });
    setResumes(prev => [...prev, ...newFiles]);
  };

  const removeResume = (id: string) => {
    setResumes(prev => prev.filter(f => f.id !== id));
  };

  const startAnalysis = async () => {
    if (!jd.trim() || resumes.length === 0) return;

    setIsAnalyzing(true);
    setView('dashboard');

    const updatedResumes = [...resumes];

    for (let i = 0; i < updatedResumes.length; i++) {
      if (updatedResumes[i].status === 'completed') continue;

      try {
        updatedResumes[i].status = 'processing';
        setResumes([...updatedResumes]);

        const file = updatedResumes[i].file;
        if (!file) throw new Error("File object is missing");

        const reader = new FileReader();
        const contentPromise = new Promise<string>((resolve) => {
          reader.onload = () => {
            const result = reader.result as string;
            resolve(file.type.startsWith('image/') ? result.split(',')[1] : result);
          };
          if (file.type.startsWith('image/')) {
            reader.readAsDataURL(file);
          } else {
            reader.readAsText(file);
          }
        });

        const content = await contentPromise;
        updatedResumes[i].content = content;

        const result = await analyzeResume(jd, {
          name: updatedResumes[i].name,
          type: updatedResumes[i].type,
          content: content
        });

        updatedResumes[i].result = result;
        updatedResumes[i].status = 'completed';
      } catch (error) {
        console.error("Error analyzing resume:", error);
        updatedResumes[i].status = 'error';
      }
      setResumes([...updatedResumes]);
    }

    setIsAnalyzing(false);
  };

  const completedAnalyses = resumes
    .filter(r => r.status === 'completed' && r.result)
    .map(r => r.result as AnalysisResult);

  if (view === 'dashboard') {
    return <AnalysisDashboard 
             results={completedAnalyses} 
             isAnalyzing={isAnalyzing} 
             jd={jd}
             onBack={() => setView('setup')}
           />;
  }

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-4 sm:p-6 lg:p-8 animate-fadeIn">
      <div className="w-full max-w-6xl mx-auto">
        <header className="text-center mb-10">
          <h1 className="text-4xl sm:text-5xl font-bold text-slate-100">
            <span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-400 to-purple-500">SmartScout</span>
          </h1>
          <p className="mt-2 text-lg text-slate-400">AI-Powered Candidate Screening</p>
        </header>

        <main className="space-y-8">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="space-y-4">
              <h3 className="text-xl font-bold text-slate-200 flex items-center gap-2">
                <span className="flex items-center justify-center w-8 h-8 rounded-full bg-slate-800 border border-slate-700 text-indigo-400 font-bold">1</span>
                Job Description
              </h3>
              <JDInput value={jd} onChange={setJd} />
            </div>
            <div className="space-y-4">
              <h3 className="text-xl font-bold text-slate-200 flex items-center gap-2">
                <span className="flex items-center justify-center w-8 h-8 rounded-full bg-slate-800 border border-slate-700 text-indigo-400 font-bold">2</span>
                Upload Resumes
              </h3>
              <FileUpload resumes={resumes} onUpload={handleUpload} onRemove={removeResume} />
            </div>
          </div>

          <div className="flex justify-center pt-8">
            <button
              onClick={startAnalysis}
              disabled={!jd.trim() || resumes.length === 0 || isAnalyzing}
              className="px-10 py-4 rounded-xl font-bold text-lg transition-all transform hover:scale-105 flex items-center gap-3 relative overflow-hidden disabled:opacity-50 disabled:cursor-not-allowed disabled:scale-100 disabled:bg-slate-700 disabled:text-slate-400 bg-gradient-to-r from-indigo-500 to-purple-600 text-white glow-shadow"
            >
              {isAnalyzing ? "Processing..." : "Start Analysis"}
            </button>
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React from 'react';

