import React from 'react';
import { ResumeFile } from '../types';

interface FileUploadProps {
  resumes: ResumeFile[];
  onUpload: (files: FileList) => void;
  onRemove: (id: string) => void;
}

const FileUpload: React.FC<FileUploadProps> = ({ resumes, onUpload, onRemove }) => {
  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      onUpload(e.target.files);
    }
  };

  return (
    <div className="space-y-4 h-full flex flex-col">
      <div className="border-2 border-dashed border-slate-700 rounded-xl p-6 text-center bg-slate-800/50 hover:border-indigo-500/80 hover:bg-slate-800/70 transition-all cursor-pointer group relative flex-grow flex flex-col justify-center">
        <input
          type="file"
          multiple
          accept=".pdf,.png,.jpg,.jpeg,.txt"
          className="absolute inset-0 opacity-0 cursor-pointer"
          onChange={handleFileChange}
        />
        <div className="flex flex-col items-center">
          <svg className="w-10 h-10 mb-3 text-slate-500 group-hover:text-indigo-400 transition-colors" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" d="M12 16.5V9.75m0 0l-3.75 3.75M12 9.75l3.75 3.75M3 17.25V6.75A2.25 2.25 0 015.25 4.5h13.5A2.25 2.25 0 0121 6.75v10.5A2.25 2.25 0 0118.75 19.5H5.25A2.25 2.25 0 013 17.25z" />
          </svg>
          <p className="text-slate-300 font-medium">Drop files here or click to upload</p>
          <p className="text-xs text-slate-500 mt-1">PDF, TXT, PNG, JPG</p>
        </div>
      </div>

      <div className="grid grid-cols-1 gap-2 max-h-[190px] overflow-y-auto custom-scrollbar pr-2">
        {resumes.map((file) => (
          <div key={file.id} className="bg-slate-800 p-3 rounded-lg border border-slate-700 flex items-center justify-between group animate-fadeIn">
            <div className="flex items-center gap-3 overflow-hidden">
              <div className="text-indigo-400">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
              </div>
              <div className="truncate">
                <p className="text-sm font-medium text-slate-200 truncate">{file.name}</p>
                <span className={`text-[10px] font-bold uppercase ${
                    file.status === 'completed' ? 'text-green-400' : 
                    file.status === 'processing' ? 'text-blue-400' : 
                    file.status === 'error' ? 'text-red-400' : 'text-slate-400'
                  }`}>{file.status}</span>
              </div>
            </div>

            <button onClick={() => onRemove(file.id)} className="text-slate-500 hover:text-red-400 p-1 rounded-full opacity-50 group-hover:opacity-100 transition-all">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </div>
        ))}
      </div>
    </div>
  );
};

export default FileUpload;

import React, { useState, useMemo } from 'react';
import { AnalysisResult, InterviewQuestions, ScoringBreakdown } from '../types';
import { generateInterviewQuestions } from '../services/geminiService';

// Sub-components defined within the same file for simplicity

// Left Panel: Candidate List
const CandidateList = ({ results, selected, onSelect, onBack }) => (
  <div className="bg-slate-900/70 flex flex-col h-full rounded-l-xl border-r border-slate-700">
    <div className="p-4 border-b border-slate-700 flex items-center justify-between">
      <button onClick={onBack} className="text-sm text-slate-300 hover:text-white flex items-center gap-2">
        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 19l-7-7 7-7" /></svg>
        New Analysis
      </button>
      <h2 className="text-lg font-bold text-white">Candidates</h2>
    </div>
    <div className="flex-1 overflow-y-auto custom-scrollbar">
      {results.map((candidate, index) => (
        <div
          key={candidate.candidateName}
          onClick={() => onSelect(candidate)}
          className={`p-4 border-b border-slate-800 cursor-pointer transition-all ${
            selected?.candidateName === candidate.candidateName ? 'bg-indigo-600/30' : 'hover:bg-slate-800/60'
          }`}
        >
          <div className="flex justify-between items-center mb-1">
            <h3 className="font-bold text-slate-100 truncate">{candidate.candidateName}</h3>
            <span className={`text-xl font-bold ${candidate.overallScore > 80 ? 'text-green-400' : 'text-blue-400'}`}>
              {candidate.overallScore}
            </span>
          </div>
          <p className="text-xs text-slate-400">{candidate.recommendation}</p>
        </div>
      ))}
    </div>
  </div>
);

// Right Panel: JD Viewer
const JDViewer = ({ jd }) => (
  <div className="bg-slate-900/70 flex flex-col h-full rounded-r-xl border-l border-slate-700">
     <div className="p-4 border-b border-slate-700">
      <h2 className="text-lg font-bold text-white">Job Description</h2>
    </div>
    <div className="p-4 overflow-y-auto custom-scrollbar text-sm leading-relaxed whitespace-pre-wrap">
      {jd}
    </div>
  </div>
);

// Center Panel: Candidate Details
const CandidateDetailView = ({ candidate, jd }) => {
  const [activeTab, setActiveTab] = useState('overview');
  const [questions, setQuestions] = useState<InterviewQuestions | null>(candidate.interviewQuestions || null);
  const [isLoadingQuestions, setIsLoadingQuestions] = useState(false);

  const handleGenerateQuestions = async () => {
    if (!candidate || !jd || questions) return;
    setIsLoadingQuestions(true);
    try {
      const result = await generateInterviewQuestions(jd, candidate);
      setQuestions(result);
      candidate.interviewQuestions = result; // Cache on the object
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoadingQuestions(false);
    }
  };

  if (!candidate) {
    return (
      <div className="flex items-center justify-center h-full text-center">
        <div>
          <svg className="w-16 h-16 mx-auto text-slate-600" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" d="M15.75 6a3.75 3.75 0 11-7.5 0 3.75 3.75 0 017.5 0zM4.501 20.118a7.5 7.5 0 0114.998 0A17.933 17.933 0 0112 21.75c-2.676 0-5.216-.584-7.499-1.632z" /></svg>
          <h3 className="mt-4 text-xl font-bold text-slate-200">Select a Candidate</h3>
          <p className="text-slate-400">Choose a candidate from the left panel to see their detailed analysis.</p>
        </div>
      </div>
    );
  }

  const tabs = ['overview', 'scorecard', 'interview'];

  return (
    <div className="flex flex-col h-full p-6">
      <header className="mb-6">
        <h1 className="text-3xl font-bold text-white">{candidate.candidateName}</h1>
        <p className="text-indigo-400 font-semibold">{candidate.recommendation}</p>
      </header>

      <nav className="flex border-b border-slate-700 mb-6">
        {tabs.map(tab => (
          <button
            key={tab}
            onClick={() => setActiveTab(tab)}
            className={`capitalize px-4 py-3 text-sm font-medium transition-colors ${
              activeTab === tab 
              ? 'border-b-2 border-indigo-500 text-white' 
              : 'text-slate-400 hover:text-white'
            }`}
          >
            {tab}
          </button>
        ))}
      </nav>

      <div className="flex-1 overflow-y-auto custom-scrollbar pr-2 animate-fadeIn">
        {activeTab === 'overview' && (
          <div className="space-y-6">
            <div>
              <h4 className="font-bold text-slate-200 mb-2">AI Summary</h4>
              <p className="text-slate-300 bg-slate-800/50 p-4 rounded-lg border border-slate-700">{candidate.summary}</p>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <h4 className="font-bold text-green-400 mb-2">Strengths</h4>
                <ul className="list-disc list-inside space-y-2 text-slate-300">
                  {candidate.strengths.map(s => <li key={s}>{s}</li>)}
                </ul>
              </div>
              <div>
                <h4 className="font-bold text-orange-400 mb-2">Gaps</h4>
                <ul className="list-disc list-inside space-y-2 text-slate-300">
                  {candidate.gaps.map(g => <li key={g}>{g}</li>)}
                </ul>
              </div>
            </div>
          </div>
        )}
        {activeTab === 'scorecard' && (
          <div className="space-y-4">
            {candidate.breakdown.map((item: ScoringBreakdown) => (
              <div key={item.parameter}>
                <div className="flex justify-between items-center mb-1">
                  <span className="font-medium text-slate-200">{item.parameter}</span>
                  <span className="font-bold text-blue-300">{item.score}/{item.maxScore}</span>
                </div>
                <div className="w-full bg-slate-700 rounded-full h-2.5">
                  <div className="bg-gradient-to-r from-indigo-500 to-blue-500 h-2.5 rounded-full" style={{width: `${(item.score / item.maxScore) * 100}%`}}></div>
                </div>
                <p className="text-xs text-slate-400 mt-2">{item.reasoning}</p>
              </div>
            ))}
          </div>
        )}
        {activeTab === 'interview' && (
          <div>
            {!questions && !isLoadingQuestions && (
              <button onClick={handleGenerateQuestions} className="px-5 py-2 rounded-lg font-semibold transition-all bg-gradient-to-r from-indigo-500 to-purple-600 text-white hover:scale-105 glow-shadow">
                Generate Interview Questions
              </button>
            )}
            {isLoadingQuestions && <p className="text-slate-400">Generating questions...</p>}
            {questions && (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6 animate-fadeIn">
                <div>
                  <h4 className="font-bold text-green-400 mb-2">Validate Strengths</h4>
                  <ul className="list-disc list-inside space-y-2 text-slate-300">
                    {questions.strengths.map(q => <li key={q}>{q}</li>)}
                  </ul>
                </div>
                <div>
                  <h4 className="font-bold text-orange-400 mb-2">Probe Gaps</h4>
                  <ul className="list-disc list-inside space-y-2 text-slate-300">
                    {questions.gaps.map(q => <li key={q}>{q}</li>)}
                  </ul>
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};


interface AnalysisDashboardProps {
  results: AnalysisResult[];
  isAnalyzing: boolean;
  jd: string;
  onBack: () => void;
}

const AnalysisDashboard: React.FC<AnalysisDashboardProps> = ({ results, isAnalyzing, jd, onBack }) => {
  const sortedResults = useMemo(() => [...results].sort((a, b) => b.overallScore - a.overallScore), [results]);
  const [selectedCandidate, setSelectedCandidate] = useState<AnalysisResult | null>(sortedResults.length > 0 ? sortedResults[0] : null);

  if (isAnalyzing && results.length === 0) {
    return (
      <div className="flex h-screen items-center justify-center text-center">
        <div>
          <div className="w-16 h-16 border-4 border-slate-700 border-t-indigo-500 rounded-full animate-spin mx-auto"></div>
          <h3 className="mt-6 text-xl font-bold text-slate-200">Analyzing Resumes...</h3>
          <p className="text-slate-400 mt-2">The AI is scoring candidates against the job description.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="h-screen w-screen p-4 flex items-center justify-center animate-fadeIn">
      <div className="w-full h-full max-w-screen-2xl mx-auto grid grid-cols-[300px_1fr_350px] gap-4">
        <CandidateList results={sortedResults} selected={selectedCandidate} onSelect={setSelectedCandidate} onBack={onBack} />
        <main className="bg-slate-800/50 rounded-xl border border-slate-700 h-full overflow-hidden">
          <CandidateDetailView candidate={selectedCandidate} jd={jd} />
        </main>
        <JDViewer jd={jd} />
      </div>
    </div>
  );
};

export default AnalysisDashboard;

export interface ScoringBreakdown {
  parameter: string;
  score: number;
  maxScore: number;
  reasoning: string;
}

export interface InterviewQuestions {
  strengths: string[];
  gaps: string[];
}

export interface AnalysisResult {
  candidateName: string;
  overallScore: number;
  breakdown: ScoringBreakdown[];
