import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { AnalysisResult, InterviewQuestions } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeResume = async (
  jd: string,
  resumeData: { name: string; type: string; content: string }
): Promise<AnalysisResult> => {
  const model = "gemini-3-flash-preview";

  const prompt = `
    Task: Act as an expert HR Recruiter. Analyze the provided Resume against the Job Description (JD).

    Job Description:
    ${jd}

    Instructions:
    1. Extract the candidate's name from the resume. If no clear name is found, use the filename as a placeholder.
    2. Score the candidate on a scale of 0-100 across 5 parameters: Technical Skills, Soft Skills, Relevant Experience, Education Alignment, and Overall Cultural Fit.
    3. Provide a concise summary of the candidate's profile.
    4. List exactly 3 key strengths and exactly 3 key gaps.
    5. Provide a final recommendation ('Highly Recommend', 'Recommend', 'Consider', 'Reject').
  `;

  const isImage = resumeData.type.startsWith('image/');

  const contents = isImage 
    ? {
        parts: [
          { text: prompt },
          { inlineData: { mimeType: resumeData.type, data: resumeData.content } }
        ]
      }
    : {
        parts: [
          { text: prompt },
          { text: `Resume Content:\n${resumeData.content}` }
        ]
      };

  const response = await ai.models.generateContent({
    model,
    contents,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          candidateName: { type: Type.STRING },
          overallScore: { type: Type.NUMBER },
          breakdown: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                parameter: { type: Type.STRING },
                score: { type: Type.NUMBER },
                maxScore: { type: Type.NUMBER },
                reasoning: { type: Type.STRING }
              },
              required: ["parameter", "score", "maxScore", "reasoning"]
            }
          },
          summary: { type: Type.STRING },
          strengths: { type: Type.ARRAY, items: { type: Type.STRING } },
          gaps: { type: Type.ARRAY, items: { type: Type.STRING } },
          recommendation: { type: Type.STRING }
        },
        required: ["candidateName", "overallScore", "breakdown", "summary", "strengths", "gaps", "recommendation"]
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("Empty response from AI");

  return JSON.parse(text) as AnalysisResult;
};

export const generateInterviewQuestions = async (
  jd: string,
  analysis: AnalysisResult
): Promise<InterviewQuestions> => {
  const model = "gemini-3-flash-preview";

  const prompt = `
    Act as a senior hiring manager preparing for an interview. Based on the Job Description and the candidate's analysis (summary, strengths, and gaps), generate insightful, open-ended interview questions.

    - Generate exactly 2 questions to validate their key strengths and understand the depth of their expertise.
    - Generate exactly 2 questions to probe their potential gaps or areas for development in a constructive manner.

    Job Description:
    ${jd}

    Candidate Analysis:
    Name: ${analysis.candidateName}
    Summary: ${analysis.summary}
    Strengths: ${analysis.strengths.join(', ')}
    Gaps: ${analysis.gaps.join(', ')}
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          strengths: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "Questions to validate candidate's strengths."
          },
          gaps: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "Questions to probe candidate's gaps."
          }
        },
        required: ["strengths", "gaps"]
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("Empty response from AI");

  return JSON.parse(text) as InterviewQuestions;
}

import React, { useState } from 'react';
import JDInput from './components/JDInput';
import FileUpload from './components/FileUpload';
import AnalysisDashboard from './components/AnalysisDashboard';
import { ResumeFile, AnalysisResult } from './types';
import { analyzeResume } from './services/geminiService';

const App: React.FC = () => {
  const [jd, setJd] = useState('');
  const [resumes, setResumes] = useState<ResumeFile[]>([]);
  const [view, setView] = useState<'setup' | 'dashboard'>('setup');
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const handleUpload = async (files: FileList) => {
    const newFiles: ResumeFile[] = Array.from(files).map(file => {
      const id = Math.random().toString(36).substr(2, 9);
      return {
        id,
        name: file.name,
        type: file.type,
        file, // Store the file object
        content: '', // Will be loaded on demand
        status: 'pending'
      } as ResumeFile;
    });
    setResumes(prev => [...prev, ...newFiles]);
  };

  const removeResume = (id: string) => {
    setResumes(prev => prev.filter(f => f.id !== id));
  };

  const startAnalysis = async () => {
    if (!jd.trim() || resumes.length === 0) return;

    setIsAnalyzing(true);
    setView('dashboard');

    const updatedResumes = [...resumes];

    for (let i = 0; i < updatedResumes.length; i++) {
      if (updatedResumes[i].status === 'completed') continue;

      try {
        updatedResumes[i].status = 'processing';
        setResumes([...updatedResumes]);

        const file = updatedResumes[i].file;
        if (!file) throw new Error("File object is missing");

        const reader = new FileReader();
        const contentPromise = new Promise<string>((resolve) => {
          reader.onload = () => {
            const result = reader.result as string;
            resolve(file.type.startsWith('image/') ? result.split(',')[1] : result);
          };
          if (file.type.startsWith('image/')) {
            reader.readAsDataURL(file);
          } else {
            reader.readAsText(file);
          }
        });

        const content = await contentPromise;
        updatedResumes[i].content = content;

        const result = await analyzeResume(jd, {
          name: updatedResumes[i].name,
          type: updatedResumes[i].type,
          content: content
        });

        updatedResumes[i].result = result;
        updatedResumes[i].status = 'completed';
      } catch (error) {
        console.error("Error analyzing resume:", error);
        updatedResumes[i].status = 'error';
      }
      setResumes([...updatedResumes]);
    }

    setIsAnalyzing(false);
  };

  const completedAnalyses = resumes
    .filter(r => r.status === 'completed' && r.result)
    .map(r => r.result as AnalysisResult);

  if (view === 'dashboard') {
    return <AnalysisDashboard 
             results={completedAnalyses} 
             isAnalyzing={isAnalyzing} 
             jd={jd}
             onBack={() => {
               setView('setup');
               setJd('');
               setResumes([]);
             }}
           />;
  }

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-4 sm:p-6 lg:p-8">
      <div className="w-full max-w-4xl mx-auto">
        <header className="text-center mb-12">
          <h1 className="text-4xl sm:text-5xl font-bold text-slate-100">
            <span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-400 to-purple-500">SmartScout</span>
          </h1>
          <p className="mt-2 text-lg text-slate-400">AI-Powered Candidate Screening</p>
        </header>

        <main className="w-full max-w-3xl mx-auto space-y-12">
           <section className="animate-fadeIn" style={{animationDelay: '100ms'}}>
            <h3 className="text-xl font-bold text-slate-200 flex items-center gap-3 mb-4">
              <span className="flex items-center justify-center w-8 h-8 rounded-full bg-slate-800 border border-slate-700 text-indigo-400 font-bold">1</span>
              Provide Job Description
            </h3>
            <JDInput value={jd} onChange={setJd} />
          </section>

          <section className="animate-fadeIn" style={{animationDelay: '200ms'}}>
             <h3 className="text-xl font-bold text-slate-200 flex items-center gap-3 mb-4">
                <span className="flex items-center justify-center w-8 h-8 rounded-full bg-slate-800 border border-slate-700 text-indigo-400 font-bold">2</span>
                Upload Candidate Resumes
              </h3>
            <FileUpload resumes={resumes} onUpload={handleUpload} onRemove={removeResume} />
          </section>

          <section className="flex justify-center pt-4 animate-fadeIn" style={{animationDelay: '300ms'}}>
            <button
              onClick={startAnalysis}
              disabled={!jd.trim() || resumes.length === 0 || isAnalyzing}
              className="px-10 py-4 rounded-xl font-bold text-lg transition-all transform hover:scale-105 flex items-center gap-3 relative overflow-hidden disabled:opacity-50 disabled:cursor-not-allowed disabled:scale-100 disabled:bg-slate-700 disabled:text-slate-400 bg-gradient-to-r from-indigo-500 to-purple-600 text-white glow-shadow"
            >
              {isAnalyzing ? "Processing..." : "Start Analysis"}
            </button>
          </section>
        </main>
      </div>
    </div>
  );
};

export default App;

