  useEffect(() => {
    setActiveTab('overview');
    setQuestions(candidate?.interviewQuestions || null);
    setIsLoadingQuestions(false);
  }, [candidate]);

  const handleGenerateQuestions = async () => {
    if (!candidate || !jd || questions) return;
    setIsLoadingQuestions(true);
    try {
      const result = await generateInterviewQuestions(jd, candidate);
      setQuestions(result);
      if (candidate) candidate.interviewQuestions = result;
