interface AnalysisDashboardProps {
  results: AnalysisResult[];
  isAnalyzing: boolean;
  jd: string;
  onBack: () => void;
}

const AnalysisDashboard: React.FC<AnalysisDashboardProps> = ({ results, isAnalyzing, jd, onBack }) => {
  const sortedResults = useMemo(() => [...results].sort((a, b) => b.overallScore - a.overallScore), [results]);
  const [selectedCandidate, setSelectedCandidate] = useState<AnalysisResult | null>(null);

  useEffect(() => {
    if (!selectedCandidate && sortedResults.length > 0) {
      setSelectedCandidate(sortedResults[0]);
    }
  }, [sortedResults, selectedCandidate]);

  if (isAnalyzing && results.length === 0) {
    return <AnalyzingState />;
  }

  return (
    <div className="h-screen w-screen p-4 flex flex-col animate-fadeIn">
      <div className="w-full h-full max-w-screen-2xl mx-auto grid grid-cols-[300px_1fr_350px] gap-4 flex-1">
        <CandidateList results={sortedResults} selected={selectedCandidate} onSelect={setSelectedCandidate} onBack={onBack} />
        <main className="bg-slate-800 rounded-xl border border-slate-700 h-full overflow-hidden">
          <CandidateDetailView candidate={selectedCandidate} jd={jd} />
        </main>
        <JDViewer jd={jd} />
      </div>
      <footer className="text-center text-xs text-slate-600 py-2">
        Powered by SmartScout AI
      </footer>
    </div>
  );
};

